#!/usr/bin/env node
import fs from 'node:fs';
import path from 'node:path';
import { fileURLToPath } from 'node:url';

const __filename = fileURLToPath(import.meta.url);
const __dirname = path.dirname(__filename);
const POSTERS_DIR = path.join(__dirname, '..', 'public', 'posters');
const OUT = path.join(__dirname, '..', 'src', 'data', 'poster-manifest.js');

const slugs = fs
  .readdirSync(POSTERS_DIR)
  .filter((f) => f.endsWith('.png'))
  .map((f) => f.replace(/\.png$/, ''))
  .sort();

const content =
  '// AUTO-GENERATED by scripts/write-manifest.js — do not edit by hand.\n' +
  '// Regenerates on every `npm run build` and after `npm run posters`.\n' +
  'export const POSTER_SLUGS = new Set(' +
  JSON.stringify(slugs, null, 2) +
  ');\n';

fs.writeFileSync(OUT, content);
console.log(`wrote ${slugs.length} poster slugs to src/data/poster-manifest.js`);
